(function () {
  const d = document;

  // scrambled chunks (order matters later)
  const p1 = [115,101,100];        // sed
  const p2 = [99,111,110];         // con
  const p3 = [116,97,99,116];      // tact
  const p4 = [105,46];             // i.
  const p5 = [117,107];            // uk
  const p6 = [64];                 // @

  function build() {
    // reorder + merge
    const arr = [
      ...p2, ...p3,  // contact
      ...p6,         // @
      ...p1, ...p4,  // sedi.
      ...p5          // uk
    ];

    const email = String.fromCharCode.apply(null, arr);

    const a = d.createElement('a');
    a.href = 'mailto:' + email;
    a.textContent = email;

    const el = d.getElementById('e');
    if (el) el.appendChild(a);
  }

  // delay + interaction trigger combo
  let done = false;

  function trigger() {
    if (done) return;
    done = true;
    setTimeout(build, 200 + Math.random() * 300);
  }

  // multiple triggers (bots rarely simulate all)
  window.addEventListener('load', trigger);
  window.addEventListener('mousemove', trigger);
  window.addEventListener('scroll', trigger);
})();
